import{_ as s,o as e,c as t,a2 as r}from"./chunks/framework.BS3ZfcoS.js";const g=JSON.parse('{"title":"双非找工作","description":"","frontmatter":{"title":"双非找工作","author":"","collection":"职场成长","series_order":9,"total_chars":1572},"headers":[],"relativePath":"career/job-hunt.md","filePath":"career/job-hunt.md"}'),o={name:"career/job-hunt.md"};function p(n,a,l,h,i,c){return e(),t("div",null,[...a[0]||(a[0]=[r('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-517" class="page-toc-link">双非00后找工作进大厂系列</a>     <a href="#s-518" class="page-toc-link">双非00后找工作进大厂如探囊取物，赶紧来学野路子（一）</a>     <a href="#s-520" class="page-toc-link">双非00后找工作进大厂如探囊取物，赶紧来学野路子（二）</a>     <a href="#s-521" class="page-toc-link">双非00后找工作进大厂如探囊取物，赶紧来学野路子（三）</a><a href="#s-596" class="page-toc-link">普通本科找工作系列</a>     <a href="#s-597" class="page-toc-link">普通本科找工作（上）——从二本到大厂</a>     <a href="#s-600" class="page-toc-link">普通本科找工作（中）——学术vs实战两条路</a>     <a href="#s-601" class="page-toc-link">普通本科找工作（下）——过好现实的生活</a></div><h2 id="s-517" tabindex="-1">双非00后找工作进大厂系列 <a class="header-anchor" href="#s-517" aria-label="Permalink to &quot;双非00后找工作进大厂系列 {#s-517}&quot;">​</a></h2><p>共3个视频</p><h3 id="s-518" tabindex="-1">双非00后找工作进大厂如探囊取物，赶紧来学野路子（一） <a class="header-anchor" href="#s-518" aria-label="Permalink to &quot;双非00后找工作进大厂如探囊取物，赶紧来学野路子（一） {#s-518}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **成交思维——把自己当产品，多渠道触达目标用户（管理者、小老板），不要只靠海投简历</p><p>**2. **绕过中间商直接成交——当简历可能被算法或HR刷掉时，可以直接触达业务负责人，打动他后他会帮你和HR沟通</p><h4 id="s-519" tabindex="-1">3. 主动到职场人活跃的地方（垂类社群、线上下分享会）做自我介绍、刷存在感 <a class="header-anchor" href="#s-519" aria-label="Permalink to &quot;3. 主动到职场人活跃的地方（垂类社群、线上下分享会）做自我介绍、刷存在感 {#s-519}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「当你觉得你的简历可能会被算法给刷掉或者会被HR给忽视的时候，你可以绕过这些然后直接去触达一位背后的业务负责人」</em></p><p><strong>行动指南</strong></p><p>加入职场所群、参加分享会，主动向业务负责人做自我介绍</p><h3 id="s-520" tabindex="-1">双非00后找工作进大厂如探囊取物，赶紧来学野路子（二） <a class="header-anchor" href="#s-520" aria-label="Permalink to &quot;双非00后找工作进大厂如探囊取物，赶紧来学野路子（二） {#s-520}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **个人说明书——自我介绍文档包含基本信息+客户证言（别人夸你的截图）+体系化作品+友情链接，侧面体现你的价值</p><p>**2. **仔细研究JD，从过往经历中挖掘匹配部分并讲故事；实在没有相关经验就&quot;无中生有&quot;，创造与JD相关的作品</p><p>**3. **大厂实习转正虽难，但大厂信息密度高能带来高认知；小公司如果团队成员Level高也很有价值</p><p><strong>金句</strong></p><p><em>「如果没有一些通用的能够证明你很强的能力，就去创造一些与JD相关的作品，咱就是一个无中生有」</em></p><p><strong>行动指南</strong></p><p>制作个人说明书，根据JD定制作品集，用作品在面试中反客为主</p><h3 id="s-521" tabindex="-1">双非00后找工作进大厂如探囊取物，赶紧来学野路子（三） <a class="header-anchor" href="#s-521" aria-label="Permalink to &quot;双非00后找工作进大厂如探囊取物，赶紧来学野路子（三） {#s-521}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **从学生到职场的五大变化：用概念解释→拥有解决方案；想超越别人→想建立合作；给人力资源→给业务资源；闷头研究→找有经验的人聊；认真付出后的失败不算失败</p><p>**2. **最精华的知识不在现有媒介里而在人的大脑里，找具体的人聊具体的事才能获得稀缺知识</p><h4 id="s-522" tabindex="-1">3. 年轻时要主动开放地开眼界，张开双臂拥抱世界 <a class="header-anchor" href="#s-522" aria-label="Permalink to &quot;3. 年轻时要主动开放地开眼界，张开双臂拥抱世界 {#s-522}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「像一个不需要钱那样去认真地工作，像不用担心失败那样去尝试，像不用害怕碰壁那样去交朋友」</em></p><p><strong>行动指南</strong></p><p>主动开放地建立人际链接，把每次失败视为未来收获的铺垫</p><h2 id="s-596" tabindex="-1">普通本科找工作系列 <a class="header-anchor" href="#s-596" aria-label="Permalink to &quot;普通本科找工作系列 {#s-596}&quot;">​</a></h2><p>共3个视频</p><h3 id="s-597" tabindex="-1">普通本科找工作（上）——从二本到大厂 <a class="header-anchor" href="#s-597" aria-label="Permalink to &quot;普通本科找工作（上）——从二本到大厂 {#s-597}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **双非二本+考研失败+零实习的起点——面试被嘲讽&quot;也该走出象牙塔了&quot;，城市没有自己的位子</p><h4 id="s-598" tabindex="-1">2. 第一份工作翻译月薪5000到手3000多，三个月后果断离职转行互联网运营 <a class="header-anchor" href="#s-598" aria-label="Permalink to &quot;2. 第一份工作翻译月薪5000到手3000多，三个月后果断离职转行互联网运营 {#s-598}&quot;">​</a></h4><h4 id="s-599" tabindex="-1">3. 用发展的眼光看自己——与名校生的差距可以后天努力缩小直至消失 <a class="header-anchor" href="#s-599" aria-label="Permalink to &quot;3. 用发展的眼光看自己——与名校生的差距可以后天努力缩小直至消失 {#s-599}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「这个城市的钱在哪里，然后我就要去哪里」</em></p><p><strong>行动指南</strong></p><p>找到行业发展方向，在实战中积累能力，用发展眼光看待自己</p><h3 id="s-600" tabindex="-1">普通本科找工作（中）——学术vs实战两条路 <a class="header-anchor" href="#s-600" aria-label="Permalink to &quot;普通本科找工作（中）——学术vs实战两条路 {#s-600}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **学术之路：80%的人不需要考研——除非体制内/学历硬性要求，三年研究生比不上三年工作经验</p><p>**2. **实战最优路径：小公司→B轮公司→大公司——每个阶段补不同能力模块，先找到自己想深耕的领域再去大厂</p><p>**3. **头部效应——在每家公司都要做最优秀的20%，这样跃迁时别人会优先选你；进公司就想清楚离开时要带走什么成绩</p><p><strong>金句</strong></p><p><em>「你一进一家公司的时候你就应该问自己，如果有一天我要从这个公司离开，我要带走的成绩是什么」</em></p><p><strong>行动指南</strong></p><p>在每家公司争取做到前20%，明确每段经历要积累什么成绩</p><h3 id="s-601" tabindex="-1">普通本科找工作（下）——过好现实的生活 <a class="header-anchor" href="#s-601" aria-label="Permalink to &quot;普通本科找工作（下）——过好现实的生活 {#s-601}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-602" tabindex="-1">1. 家境一般学历一般建议走实战之路——工作带来的成长比学校更剧烈直接 <a class="header-anchor" href="#s-602" aria-label="Permalink to &quot;1. 家境一般学历一般建议走实战之路——工作带来的成长比学校更剧烈直接 {#s-602}&quot;">​</a></h4><p>**2. **过好现实的生活是一种了不起的能力——当你有能力照顾好自己还能帮助身边重要的人时，你会更有信心</p><h4 id="s-603" tabindex="-1">3. 用发展的眼光看待自己——学历在很多地方已经够用，你会不断变好 <a class="header-anchor" href="#s-603" aria-label="Permalink to &quot;3. 用发展的眼光看待自己——学历在很多地方已经够用，你会不断变好 {#s-603}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「过好现实的生活也是一种非常了不起的能力」</em></p><p><strong>行动指南</strong></p><p>先过好现实生活，用行动证明自己而非纠结学历</p>',59)])])}const u=s(o,[["render",p]]);export{g as __pageData,u as default};
